import { GoogleGenAI } from "@google/genai";
import { ClassificationType } from "../types";

const getSystemInstruction = () => `
You are a friendly, enthusiastic teacher explaining "Unsupervised Learning" to a 7-year-old child. 
The child has just played a game where they sorted emojis into groups without being told the rules.
Keep your explanation very short (max 2-3 sentences), fun, and encouraging.
Use emojis in your response.
`;

export const getAIExplanation = async (classificationType: ClassificationType): Promise<string> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.warn("API Key not found, returning fallback text.");
      return "Wow! You found a pattern all by yourself! That's just how smart computers learn!";
    }

    const ai = new GoogleGenAI({ apiKey });

    let prompt = "";

    switch (classificationType) {
        case ClassificationType.BY_CATEGORY:
            prompt = "The child successfully sorted items by Category (Animals, Food, Objects). Explain how this is like clustering in AI.";
            break;
        case ClassificationType.BY_COLOR:
            prompt = "The child successfully sorted items by Color (Red, Green, Blue). Explain how this is like clustering in AI.";
            break;
        case ClassificationType.MIXED:
            prompt = "The child made groups that are a mix of things. Encourage them to try to find a clear pattern like 'Color' or 'Type' next time.";
            break;
        default:
            return "Great job playing!";
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: getSystemInstruction(),
      }
    });

    return response.text || "You are learning just like a computer does!";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "You grouped them together perfectly! Machines learn by finding patterns just like you did!";
  }
};

import React from 'react';
import { EmojiItem } from '../types';

interface DraggableItemProps {
  item: EmojiItem;
  onDragStart: (e: React.DragEvent<HTMLDivElement>, itemId: string) => void;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ item, onDragStart }) => {
  return (
    <div
