import React, { useState, useMemo } from 'react';
import { ITEMS, INITIAL_LOCATIONS } from './constants';
import { ClassificationType, Category, ItemColor, Location } from './types';
import { DraggableItem } from './components/DraggableItem';
import { DropBin } from './components/DropBin';
import { getAIExplanation } from './services/geminiService';
import { RefreshCcw, CheckCircle2, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [itemLocations, setItemLocations] = useState<Record<string, string>>(INITIAL_LOCATIONS);
  const [dragOverBin, setDragOverBin] = useState<string | null>(null);
  const [result, setResult] = useState<{ type: ClassificationType; message: string; aiMessage?: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  // Drag Handlers
  const handleDragStart = (e: React.DragEvent<HTMLDivElement>, itemId: string) => {
    e.dataTransfer.setData('itemId', itemId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>, binId: string) => {
    e.preventDefault(); // Necessary to allow dropping
    if (dragOverBin !== binId) {
      setDragOverBin(binId);
    }
  };

  const handleDragLeave = () => {
    setDragOverBin(null);
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>, targetLocation: Location) => {
    e.preventDefault();
    const itemId = e.dataTransfer.getData('itemId');
    setDragOverBin(null);

    if (itemId) {
      setItemLocations((prev) => ({
        ...prev,
        [itemId]: targetLocation,
      }));
    }
  };

  // Logic to verify how the child sorted the items
  const checkClassification = async () => {
    const bins = ['bin1', 'bin2', 'bin3'];

    // Get items in each bin
    const binContents = bins.map(bin => 
      ITEMS.filter(item => itemLocations[item.id] === bin)
    );

    // If any bin is empty, it's not a complete classification 
    // (though strictly unsupervised learning can have empty clusters, for this game we want 3 groups)
    const emptyBins = binContents.filter(c => c.length === 0).length;
    if (emptyBins > 0) {
       setResult({
        type: ClassificationType.EMPTY,
        message: "Please put at least one item in each box!"
      });
      return;
    }

    // Calculate Purity for Category
    let categoryMatches = 0;
    binContents.forEach(binItems => {
        if (binItems.length === 0) return;
        const counts = binItems.reduce((acc, item) => {
            acc[item.category] = (acc[item.category] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
        const maxCount = Math.max(...Object.values(counts));
        categoryMatches += maxCount;
    });
    const categoryScore = categoryMatches / ITEMS.filter(i => itemLocations[i.id] !== 'pool').length;

    // Calculate Purity for Color
    let colorMatches = 0;
    binContents.forEach(binItems => {
        if (binItems.length === 0) return;
        const counts = binItems.reduce((acc, item) => {
            acc[item.color] = (acc[item.color] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
        const maxCount = Math.max(...Object.values(counts));
        colorMatches += maxCount;
    });
    const colorScore = colorMatches / ITEMS.filter(i => itemLocations[i.id] !== 'pool').length;

    // Determine Result
    let type = ClassificationType.MIXED;
    let message = "Interesting sorting! You found a unique way to group them.";

    // Thresholds (0.8 allows for a small mistake)
    if (categoryScore > 0.85) {
        type = ClassificationType.BY_CATEGORY;
        message = "Wow! You sorted them by TYPE (Animals, Food, and Things)!";
    } else if (colorScore > 0.85) {
        type = ClassificationType.BY_COLOR;
        message = "Amazing! You sorted them by COLOR (Red, Green, and Blue)!";
    }

    setResult({ type, message });

    // Fetch AI explanation
    if (process.env.API_KEY) {
        setLoadingAI(true);
        const aiMsg = await getAIExplanation(type);
        setResult(prev => prev ? { ...prev, aiMessage: aiMsg } : null);
        setLoadingAI(false);
    }
  };

  const resetGame = () => {
    setItemLocations(INITIAL_LOCATIONS);
    setResult(null);
    setLoadingAI(false);
  };

  // Group items for rendering
  const poolItems = useMemo(() => ITEMS.filter(i => itemLocations[i.id] === 'pool'), [itemLocations]);
  const bin1Items = useMemo(() => ITEMS.filter(i => itemLocations[i.id] === 'bin1'), [itemLocations]);
  const bin2Items = useMemo(() => ITEMS.filter(i => itemLocations[i.id] === 'bin2'), [itemLocations]);
  const bin3Items = useMemo(() => ITEMS.filter(i => itemLocations[i.id] === 'bin3'), [itemLocations]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 p-4 md:p-8">
      <div className="max-w-4xl mx-auto flex flex-col h-full gap-6">

        {/* Header */}
        <header className="text-center space-y-2">
          <div className="inline-flex items-center gap-2 bg-indigo-100 text-indigo-700 px-4 py-1 rounded-full text-sm font-bold uppercase tracking-wider">
            <BrainCircuit size={18} />
            <span>Mini AI Lab</span>
          </div>
          <h1 className="text-3xl md:text-4xl font-extrabold text-slate-900">
            Emoji Sorting Challenge
          </h1>
          <p className="text-slate-500 max-w-lg mx-auto">
            Drag the emojis into the boxes below. Can you find the secret patterns?
            There is no single "right" answer!
          </p>
        </header>

        {/* Game Area */}
        <main className="flex-1 flex flex-col gap-8">

          {/* Result Overlay / Message Area */}
          {result && (
            <div className={`
              p-6 rounded-2xl text-center shadow-lg border-2 animate-fade-in
              ${result.type === ClassificationType.EMPTY ? 'bg-amber-50 border-amber-200 text-amber-800' : 
                result.type === ClassificationType.MIXED ? 'bg-purple-50 border-purple-200 text-purple-800' : 
                'bg-green-50 border-green-200 text-green-800'}
            `}>
              <h2 className="text-2xl font-bold mb-2">{result.message}</h2>
              {loadingAI ? (
                 <div className="flex items-center justify-center gap-2 text-sm opacity-70 mt-2">
                    <span className="animate-spin">✨</span> Asking the AI teacher...
                 </div>
              ) : (
                result.aiMessage && (
                  <div className="mt-3 bg-white/60 p-4 rounded-xl text-lg font-medium">
                    <span className="text-2xl mr-2">🤖</span>
                    "{result.aiMessage}"
                  </div>
                )
              )}
            </div>
          )}

          {/* Bins */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <DropBin 
              id="bin1" 
              title="Group A" 
              isOver={dragOverBin === 'bin1'}
              onDrop={handleDrop} 
              onDragOver={(e) => handleDragOver(e, 'bin1')}
              onDragLeave={handleDragLeave}
            >
              {bin1Items.map(item => <DraggableItem key={item.id} item={item} onDragStart={handleDragStart} />)}
            </DropBin>

            <DropBin 
              id="bin2" 
              title="Group B" 
              isOver={dragOverBin === 'bin2'}
              onDrop={handleDrop} 
              onDragOver={(e) => handleDragOver(e, 'bin2')}
              onDragLeave={handleDragLeave}
            >
              {bin2Items.map(item => <DraggableItem key={item.id} item={item} onDragStart={handleDragStart} />)}
            </DropBin>

            <DropBin 
              id="bin3" 
              title="Group C" 
              isOver={dragOverBin === 'bin3'}
              onDrop={handleDrop} 
              onDragOver={(e) => handleDragOver(e, 'bin3')}
              onDragLeave={handleDragLeave}
            >
              {bin3Items.map(item => <DraggableItem key={item.id} item={item} onDragStart={handleDragStart} />)}
            </DropBin>
          </div>

          {/* Pool */}
          <div className={`
            bg-white p-6 rounded-3xl shadow-sm border border-slate-200 min-h-[160px] flex flex-col items-center gap-4 transition-all duration-500
            ${poolItems.length === 0 ? 'opacity-50 grayscale' : ''}
          `}>
             <h3 className="text-slate-400 font-bold uppercase tracking-wider text-xs">
                Items to Sort ({poolItems.length} left)
             </h3>
             <div className="flex flex-wrap gap-3 justify-center">
                {poolItems.map(item => (
                  <DraggableItem key={item.id} item={item} onDragStart={handleDragStart} />
                ))}
                {poolItems.length === 0 && (
                  <div className="text-slate-300 italic font-medium py-4">All items sorted! Click finish below.</div>
                )}
             </div>
          </div>

        </main>

        {/* Footer / Controls */}
        <footer className="sticky bottom-4 md:bottom-8 flex justify-center gap-4 z-10">
          <button
            onClick={resetGame}
            className="flex items-center gap-2 px-6 py-3 rounded-full bg-white border border-slate-200 shadow-md font-bold text-slate-600 hover:bg-slate-50 hover:shadow-lg transition-all active:scale-95"
          >
            <RefreshCcw size={20} />
            <span>Reset</span>
          </button>

          <button
            onClick={checkClassification}
            className="flex items-center gap-2 px-8 py-3 rounded-full bg-indigo-600 text-white shadow-lg shadow-indigo-200 font-bold text-lg hover:bg-indigo-700 hover:shadow-indigo-300 transition-all active:scale-95 ring-4 ring-white"
          >
            <CheckCircle2 size={24} />
            <span>Finish!</span>
          </button>
        </footer>

      </div>
    </div>
  );
};

export default App;

